if let Some(async_settlement) = transaction.as_async_settlement().map(|tx| tx.tx()) {
    receipt.origin_tx = Some(async_settlement.origin_tx);
    receipt.user_address = Some(async_settlement.user_address);
    receipt.total_amount = async_settlement.total_amount.try_into().ok();
    receipt.executor_address = Some(async_settlement.executor_address);
    receipt.executor_fee = async_settlement.executor_fee.try_into().ok();
    receipt.commitment_validator = Some(async_settlement.commitment_validator);
    receipt.commitment_fee = async_settlement.commitment_fee.try_into().ok();
    receipt.inclusion_validator = Some(async_settlement.inclusion_validator);
    receipt.inclusion_fee = async_settlement.inclusion_fee.try_into().ok();
    receipt.settlement_block = Some(async_settlement.settlement_block);
}
